class Solution:
    def minCameraCover(self, root):
        # states: 0 = uncovered, 1 = covered (no camera), 2 = has camera
        self.count = 0
        def dfs(node):
            if node is None:
                return 1
            l = dfs(node.left)
            r = dfs(node.right)
            if l == 0 or r == 0:
                self.count += 1
                return 2
            if l == 2 or r == 2:
                return 1
            return 0
        if dfs(root) == 0:
            self.count += 1
        return self.count

