var minCameraCover = function(root) {
    let count = 0;
    function dfs(node) {
        if (!node) return 1;
        const l = dfs(node.left);
        const r = dfs(node.right);
        if (l === 0 || r === 0) { count++; return 2; }
        if (l === 2 || r === 2) return 1;
        return 0;
    }
    if (dfs(root) === 0) count++;
    return count;
};
